package schema

import (
	"entgo.io/ent"
	"entgo.io/ent/dialect"
	"entgo.io/ent/dialect/entsql"
	"entgo.io/ent/schema/field"
	"entgo.io/ent/schema/index"
	"github.com/alpacahq/alpacadecimal"

	"github.com/openmeterio/openmeter/openmeter/mydomain"
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
)

var MyConfigScanner = entutils.JSONStringValueScanner[mydomain.Config]()

type MyEntity struct {
	ent.Schema
}

func (MyEntity) Mixin() []ent.Mixin {
	return []ent.Mixin{entutils.UniqueResourceMixin{}}
}

func (MyEntity) Fields() []ent.Field {
	return []ent.Field{
		field.Other("amount", alpacadecimal.Decimal{}).
			SchemaType(map[string]string{dialect.Postgres: "numeric"}),
		field.String("config").
			GoType(mydomain.Config{}).
			ValueScanner(MyConfigScanner).
			SchemaType(map[string]string{dialect.Postgres: "jsonb"}).
			Optional().Nillable(),
	}
}

func (MyEntity) Indexes() []ent.Index {
	return []ent.Index{
		index.Fields("namespace", "key").
			Annotations(entsql.IndexWhere("deleted_at IS NULL")).
			Unique(),
	}
}

